{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income at or below 150% of federal poverty level (varies by household size). For 2025: 1 person $2,815/month; 2 people $3,681/month; 3 people $4,547/month; 4 people $5,414/month; 5 people $6,280/month; 6 people $7,146/month. Annual example for 2-person household: $38,541 or less. Automatic eligibility if receiving SNAP, SSI, TANF, or certain veterans' benefits.[2][3]",
    "asset_limits": "No asset limit.[2]",
    "other_requirements": ["Texas resident with proof (e.g., utility bill, lease).", "U.S. citizen or qualified non-citizen (e.g., lawful permanent resident, refugee).", "Prioritizes elderly, disabled, families with young children, or energy crisis (e.g., shutoff notice).[1]"]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time payment to utility company for heating/cooling bills. Regular: $1 minimum to $12,300 maximum (heating/cooling). Crisis: up to $2,400 maximum. Also includes related weatherization (insulation, repairs).[2]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Phone: (877) 399-8939 or 211.", "Website: 211Texas.org to find local agency.", "In-person/mail: Local Community Action Agency (CAA) or CEAP subrecipient (covers all 254 counties; e.g., Travis County CEAP at (512) 584-4120).", "Online account with utility (e.g., Texas Gas Service) speeds documentation.[4]"],
    "processing_time": "Varies by region; placed on waitlist after submission, caseworker calls when turn arrives.[4]",
    "waitlist": "Yes, common; applications placed in line by site, funding-dependent.[4]",
    "forms": ["Contact local CAA for specific CEAP/LIHEAP application; no statewide form number specified.[1][4]"],
    "documents": ["Proof of income.", "Identification (Texas DL, passport).", "Recent utility bill in applicant's name.", "Proof of residency (utility bill, lease).", "Online utility statements if available.[1][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in all 254 Texas counties via local subrecipients.",
    "regional_variations": "Administered by local Community Action Agencies (CAAs) or CEAP subrecipients; guidelines, processes, wait times, and providers vary by area (e.g., Travis County CEAP has 7 locations).[1][4][6]",
    "offices_or_providers": ["Local CAAs via 211Texas.org or (877) 399-8939; full subrecipient list on TDHCA site.[4][6]"]
  },
  "official_source": "https://www.tdhca.texas.gov/comprehensive-energy-assistance-program-ceap",
  "gotchas": ["Primarily delivered as CEAP in Texas (integrates LIHEAP funds); contact local CAA, not statewide office.", "Household includes all at address sharing utility bill (unlike SNAP).", "Funding limited by federal availability; waitlists common.", "Benefits paid directly to utility, not applicant.", "Priorities for elderly/disabled/crisis, but open to all qualifying.[1][2][4]"],
  "data_shape_notes": "Administered regionally via 254 county subrecipients (CAAs/CEAP); income by household size; no asset test; benefits vary by fuel type, crisis status, and local funding; waitlists and slight guideline variations by area."
}

{
  "name": "Texas State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare-eligible individuals, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[1][2][3]",
    "asset_limits": "No asset limits or tests apply[2][3]",
    "other_requirements": ["Must be Medicare-eligible (typically age 65+ or under 65 with certain disabilities); families and caregivers also eligible[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling and assistance on Medicare options (Parts A, B, C, D, Medigap), plan reviews, applications for Medicare Savings Programs (MSP), Low-Income Subsidy (Extra Help/LIS), Medicaid; group presentations, outreach, education on fraud prevention via Senior Medicare Patrol (SMP); provided in-person, by phone, media[1][2][3][4][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-252-9240[7]", "Website: Texas Health Information, Counseling, and Advocacy Program (HICAP) site via shiphelp.org/ships/texas/[7]", "In-person or local counseling through community-based networks (contact via phone for local sites)[1][2][7]", "No specific online form or mail application mentioned; services accessed by contacting for appointment[2][3]"],
    "processing_time": "No formal application processing; counseling provided upon contact, typically immediate or by appointment[2][3]",
    "waitlist": null,
    "forms": ["No specific forms required for SHIP counseling; may assist with MSP/LIS application forms during session[2][3]"],
    "documents": ["Medicare card, current health/prescription drug plan details, income info if applying for MSP/Extra Help (prepared but not required upfront for counseling)[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to Medicare beneficiaries[1][7]",
    "regional_variations": "Delivered through local community-based networks, agencies, and providers; may have regional counselors or sites but uniform services[1][2][5][7]",
    "offices_or_providers": ["Local SHIP sites via statewide network; contact 1-800-252-9240 for nearest[1][2][7]"]
  },
  "official_source": "https://www.shiphelp.org/ships/texas/[7]",
  "gotchas": ["Not a direct healthcare or financial aid program—provides counseling only, not payments or services; in Texas called Health Information, Counseling, and Advocacy Program (HICAP); free but relies on trained volunteers/staff, so availability may depend on local capacity; often confused with Medicare Savings Programs it helps apply for[1][3][6][7]", "No enrollment wait or caps, but peak times (e.g., Open Enrollment) may have higher demand[2]"],
  "data_shape_notes": "no income/asset test; counseling service only, not benefits; statewide via local networks; Texas-specific name HICAP; volunteer-driven with national oversight by ACL[1][2][4][7]"
}

