{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are determined by federal poverty guidelines; providers assess current levels (e.g., for 2025, a single person limit around $19,000, but confirm with provider as not specified in static sources).[2]",
    "asset_limits": "No asset limits mentioned in program guidelines.",
    "other_requirements": ["Unemployed or underemployed", "Local SCSEP providers make final eligibility determination", "Priority for: age 65+, veterans/qualified spouses, individuals with disabilities, limited English proficiency, rural residents, homeless/at risk, low employment prospects, prior WIOA participants who remain unemployed, formerly incarcerated within last 5 years"][1][2]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time work (average 20 hours/week) at nonprofits/public agencies (e.g., schools, hospitals, senior centers); paid highest of federal/state/local minimum wage; on-the-job training (e.g., computer, vocational skills); job placement assistance; support classes (reading, math, resume writing, interviewing); bridge to unsubsidized jobs.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online locator: https://my.aarpfoundation.org/locator/scsep/ [5]", "Phone: Contact local provider (e.g., AARP Foundation 1-855-850-2525, MET Inc. 281-223-0099 for specific counties, Texas Workforce Commission via local Workforce Solutions offices) [1][5][6]", "In-person: Local Workforce Solutions offices, Area Agencies on Aging (AAAs), or SCSEP providers [1]", "Mail: Not specified; use provider contacts"],
    "processing_time": "Not specified; varies by local provider.",
    "waitlist": "Possible due to funding limits and county-specific availability; priority groups served first.",
    "forms": ["No specific form name/number listed; intake handled by local providers."],
    "documents": ["Proof of age (ID)", "Proof of income (tax returns, pay stubs)", "Proof of unemployment status", "Veteran/disability/rural residency documentation if claiming priority (exact list confirmed by provider)"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Operated in 82 Texas counties via sub-grantees; not all counties covered (use locator or county table for specifics).",
    "regional_variations": "Different providers per region (e.g., AARP Foundation in counties like Cameron, Dallas, El Paso; MET, Inc./CWI Works in counties like Anderson, Angelina, Lubbock; others via TWC partners); availability, wait times, and contacts vary by county/cluster.",
    "offices_or_providers": ["Texas Workforce Commission (state admin) [1]", "AARP Foundation (multiple counties e.g., Cameron, Dallas, El Paso) [5]", "MET, Inc. (e.g., Anderson to Young counties) 281-223-0099 [6]", "Local Workforce Solutions offices (28 boards statewide) [1]", "Area Agencies on Aging"]
  },
  "official_source": "https://www.twc.texas.gov/programs/senior-community-service-employment (Texas) / https://www.dol.gov/agencies/eta/seniors (federal)",
  "gotchas": ["Not available in all 254 Texas counties (only 82; check locator/county list first)", "Final eligibility by local provider, not automatic", "Part-time training wage only (not full income replacement; minimum wage level)", "Priority groups fill slots first, creating waitlists for others", "Must be actively seeking unsubsidized employment; not permanent aid", "Funding annual via DOL grants, potential changes"],
  "data_shape_notes": "County-restricted to 82 areas with multiple sub-grantees/providers (AARP Foundation, MET Inc., etc.); priority tiers heavily influence access; income at 125% FPL (federal table, varies household size); no fixed statewide application/form"
}

{
  "name": "Legal Aid for Seniors through AAAs",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict financial criteria; income and resources may be reviewed to prioritize highest need, but services are available regardless of income level[4].",
    "asset_limits": "No asset limits specified; prioritization based on need indicators like functional impairment, isolation, or low income, but not a barrier to eligibility[3][4].",
    "other_requirements": ["Texas resident aged 60 or older (or family/caregiver of such person)", "Live in a county served by one of Texas's 28 AAAs (covers all 254 counties)", "Civil legal matters only (e.g., benefits, housing, consumer issues); no criminal or personal injury cases[1][2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal aid services including one-on-one counseling on Medicare/Medicaid benefits, ombudsman advocacy for nursing homes/assisted living, referrals to legal aid organizations, and assistance with civil issues like benefits enrollment, housing, and consumer rights to support independent living[4][5]. No specific dollar amounts or hours defined; services provided as needed without charge[4].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local AAA by phone (examples: Concho Valley AAA (325) 223-5704[5], West Central Texas AAA (325) 672-8544[5], Capital Area AAA (512) 916-6062[5]; find local via Texas AAAs directory)", "In-person at local AAA offices (e.g., 2801 W. Loop 306, San Angelo, TX 76904 for Concho Valley[5]; 3702 Loop 322, Abilene, TX for West Central[5])", "Referrals through general legal aid lines like Legal Aid of NorthWest Texas (325) 677-8591[1][5] or Texas RioGrande Legal Aid (512) 374-2700[5]"],
    "processing_time": "Not specified in sources; typically immediate counseling or referral upon contact[4].",
    "waitlist": "No waitlist mentioned; services prioritized by need but available to all eligible[3][4].",
    "forms": ["No specific form names/numbers identified; intake via phone or in-person screening[1][4]"],
    "documents": ["Proof of age (e.g., ID showing 60+)", "Proof of residency/county", "Income details if prioritizing need (not required)", "Details of legal issue (e.g., Medicare statements, nursing home complaints)", "Participation proof in programs like SNAP/Medicaid/SSI for legal aid referral eligibility[1][2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must reside in service area of one of 28 AAAs, covering all 254 Texas counties[3][4].",
    "regional_variations": "Administered by 28 regional AAAs with local offices/providers; services coordinated locally, potential differences in specific offerings, wait times for prioritization, or partnered legal aid groups (e.g., Legal Aid of NorthWest Texas in north/west, Texas RioGrande in southwest[3][5][6]).",
    "offices_or_providers": ["28 AAAs including Concho Valley AAA (San Angelo), West Central Texas AAA (Abilene), Capital Area AAA (Austin area), Area Agency on Aging of Central Texas (Belton)[3][5]"]
  },
  "official_source": "https://texaslawhelp.org/article/area-agencies-on-aging-a-place-to-get-help[4]",
  "gotchas": ["Not direct legal representation; primarily counseling, ombudsman advocacy, and referrals to low-income legal aid orgs like Legal Aid of NorthWest Texas which have stricter 125-200% FPL income limits[1][2][4]", "Legal aid referrals require separate low-income eligibility (e.g., below 125-200% Federal Poverty Guidelines, U.S. citizen/LPR)[1][2]", "Prioritization for highest need (e.g., low-income minorities, rural, isolated, high nutritional risk); others may get referrals only[3][4]", "Civil matters only; no criminal/personal injury[1]", "Contact local AAA first, not statewide number[4][5]"],
  "data_shape_notes": "Decentralized across 28 regional AAAs covering all counties; no fixed income/asset tests but need-based prioritization; focuses on referrals to civil legal aid with separate eligibility; services free with ombudsman/benefit counseling core[3][4]"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial eligibility requirements apply.",
    "other_requirements": ["Must be a resident of a nursing facility or assisted living facility in Texas. Certain caregivers and family members of persons 60 years or older may also receive assistance.[2]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for residents' rights including investigating and resolving complaints, ensuring quality of life and care, providing resident rights information, monitoring laws and policies, representing residents in hearings, pursuing remedies, and protecting against abuse, neglect, or rights violations. Specific rights protected: respect/dignity, privacy, freedom from restraints/abuse, participation in care planning, choice of physician/pharmacy, grievance filing without reprisal, and access to records/inspection reports.[4][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-252-2412 to speak with a local LTC ombudsman[7]", "Email: Contact form via ltco.texas.gov[7]", "In-person: Visit local ombudsman council/agency (find via ltco.texas.gov)[7]", "Online: Use 'Find an LTC Ombudsman' tool at ltco.texas.gov[7]"],
    "processing_time": "Immediate response for complaints and advocacy; no formal processing as it's not an entitlement program.",
    "waitlist": null,
    "forms": ["No specific application forms required; contact directly to report concerns or request assistance.[2]"],
    "documents": ["No documents needed to initiate contact; provide details of the resident's situation, facility name, and specific concerns."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of nursing facilities and assisted living facilities statewide; excludes state supported living centers (separate ombudsman).[7]",
    "regional_variations": "Administered locally by Area Agencies on Aging or independent councils (e.g., H-GAC in Harris County[1][3], Texoma Council of Governments[4], CAPCOG[9], AAACP[6]); availability depends on local volunteer/staff presence but services are free and confidential statewide.",
    "offices_or_providers": ["Local programs via ltco.texas.gov 'Find an LTC Ombudsman' tool; examples: Cizik School of Nursing (Harris County)[3], Texoma COG[4]"]
  },
  "official_source": "https://ltco.texas.gov",
  "gotchas": ["Not a service provider or eligibility-determining program—purely advocacy for existing LTC residents, not for admission or financial aid.[5][9]", "Volunteers/staff must be independent with no conflicts (e.g., no facility employment or Medicaid eligibility roles).[2]", "Confidentiality applies to all complaints.[5]", "Does not cover non-LTC settings or developmental disability state centers.[7]", "People mistake it for direct care/funding; it's complaint resolution and rights protection only."],
  "data_shape_notes": "no income test; open to all LTC residents statewide via local independent councils; advocacy-focused, not benefits/entitlements; volunteer-driven with regional administration"
}
